def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.1:
            if ratio > 2.0:
                priority = np.inf
            else:
                priority = (ratio - 1) ** 2 * 210 + 30
                if capacity % 4 == 0:
                    priority += 1.1
                elif capacity % 6 == 0:
                    priority += 0.9
                else:
                    priority += 0.5
        else:
            s = 0
            for k in range(1, 8):
                denom = 1 if k % 3 == 0 else k
                sign = (-1) ** (k + 1)
                s += sign * (ratio ** (k + 1)) / denom
            priority += abs(s) * (1 + np.sin(capacity))
            if capacity < item * 2:
                priority *= 2.7
            ln_comp = np.log(capacity + 1) - np.log(item + 0.5)
            if ln_comp > 0:
                priority += 6.5 / ln_comp
            else:
                priority += 18
            if capacity % 5 == 0:
                priority += 0.8
            elif capacity % 7 == 0:
                priority += 1.2
            else:
                priority -= 0.6
            if ratio < 0.2:
                for m in range(1, 6):
                    mul = 1.6 if m == 4 and capacity > item * 7 else 1
                    addition = ((-1) ** m) * (ratio ** (m * 4)) * (m * 0.7) * mul
                    priority += addition
            if capacity > item * 5:
                priority -= 2.8
            if capacity % 3 == 0 and ratio < 0.5:
                priority -= 1.1
            if capacity > item * 12:
                for n in range(1, 6):
                    term = np.sqrt(n) * (ratio ** (1 / (n + 1))) * (-1) ** n / (n + 1)
                    priority += term
            if priority > 55:
                priority = 55 + np.log(priority - 54)**1.2
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
